section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/aws-cli-containers-iac.json",
  "type": "object",
  "required": [
    "artefact_id",
    "operation_type",
    "change_set_discipline",
    "rollback_path_documented",
    "ecs_deployment_bounds_set",
    "cloudwatch_anchor_set",
    "owner"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "stable script id"
    },
    "operation_type": {
      "type": "string",
      "description": "enum: ecs | eks | rds | cloudformation | iam | cloudwatch"
    },
    "change_set_discipline": {
      "type": "boolean",
      "description": "true for CloudFormation mutations"
    },
    "rollback_path_documented": {
      "type": "boolean",
      "description": "true for IAM mutations"
    },
    "ecs_deployment_bounds_set": {
      "type": "object",
      "description": "{minimumHealthyPercent>=50, maximumPercent<=200} when operation_type==ecs"
    },
    "cloudwatch_anchor_set": {
      "type": "string",
      "description": "URL of dashboard or alarm to watch during rollout (required for production mutations)"
    },
    "owner": {
      "type": "string",
      "description": "single named handle"
    }
  }
}
